  1→
  2→import React, { useState, useEffect } from 'react';
  3→import { createPortal } from 'react-dom';
  4→import { Shield, Zap, Globe, Check, Lock, ChevronRight, Server, Sparkles, CreditCard, Loader2, RefreshCw, ArrowLeft, Search, Filter, Star, ExternalLink, TrendingUp, ArrowRight, Plus, AlertCircle, ClipboardList, Building2, Mail, User as UserIcon, BarChart3, CheckCircle2, Award, Crown, Target, Clock } from 'lucide-react';
  5→import { AnalysisResult, CategoryScore, Recommendation } from '../types';
  6→import PageHeader from '../components/layout/PageHeader';
  7→
  8→interface DirectoryProps {
  9→  onBack: () => void;
 10→  onViewEntity: (result: AnalysisResult) => void;
 11→  onNavigateToPlan: () => void;
 12→  user: { name: string; email: string; plan: 'free' | 'pro' | 'enterprise'; credits: number } | null;
 13→  directClientCount: number;
 14→  maxClients: number;
 15→  actionPlanComplete: boolean;
 16→  actionPlanProgress: { completed: number; total: number };
 17→  onNavigateToActionPlan: () => void;
 18→}
 19→
 20→// Données simulées pour l'annuaire public
 21→const DIRECTORY_DATA = [
 22→  { id: 1, name: 'Stripe', sector: 'Fintech', aeoScore: 98, status: 'Elite', verified: true, desc: "Infrastructure de paiement pour internet." },
 23→  { id: 2, name: 'Linear', sector: 'SaaS B2B', aeoScore: 94, status: 'Elite', verified: true, desc: "Outil de gestion de projet moderne." },
 24→  { id: 3, name: 'Algolia', sector: 'Search API', aeoScore: 89, status: 'Premium', verified: true, desc: "API de recherche rapide et pertinente." },
 25→  { id: 4, name: 'Qonto', sector: 'Banque', aeoScore: 88, status: 'Premium', verified: true, desc: "La néobanque des PME et indépendants." },
 26→  { id: 5, name: 'Doctolib', sector: 'Santé', aeoScore: 85, status: 'Premium', verified: true, desc: "Plateforme de prise de rendez-vous médicaux." },
 27→  { id: 6, name: 'Alan', sector: 'Assurance', aeoScore: 92, status: 'Elite', verified: true, desc: "L'assurance santé simple et transparente." },
 28→  { id: 7, name: 'Swile', sector: 'RH', aeoScore: 78, status: 'Standard', verified: true, desc: "La carte titre-restaurant nouvelle génération." },
 29→  { id: 8, name: 'Payfit', sector: 'RH Tech', aeoScore: 81, status: 'Premium', verified: true, desc: "Gestion de la paie simplifiée." },
 30→];
 31→
 32→const SECTORS = [
 33→  'SaaS / Tech', 'E-commerce', 'Fintech', 'Santé', 'Immobilier', 'Éducation',
 34→  'Assurance', 'RH / Recrutement', 'Marketing', 'Juridique', 'Énergie', 'Autre'
 35→];
 36→
 37→const INDEXATION_PLANS = [
 38→  {
 39→    id: 'standard',
 40→    name: 'Standard',
 41→    requiredPlan: 'free' as const,
 42→    planLabel: 'Starter',
 43→    price: 'Inclus',
 44→    icon: Shield,
 45→    color: 'gray',
 46→    colorClasses: 'text-gray-400 border-gray-500/20 bg-gray-500/5',
 47→    activeClasses: 'text-white border-gray-400/40 bg-gray-500/10 ring-2 ring-gray-400/30',
 48→    features: [
 49→      'Fiche entreprise dans l\'annuaire',
 50→      'Badge "Verified" standard',
 51→      'Score AEO visible publiquement',
 52→      '1 mise à jour / mois',
 53→    ],
 54→  },
 55→  {
 56→    id: 'premium',
 57→    name: 'Premium',
 58→    requiredPlan: 'pro' as const,
 59→    planLabel: 'Pro',
 60→    price: 'Inclus',
 61→    icon: Award,
 62→    color: 'blue',
 63→    colorClasses: 'text-blue-400 border-blue-500/20 bg-blue-500/5',
 64→    activeClasses: 'text-white border-blue-400/40 bg-blue-500/10 ring-2 ring-blue-400/30',
 65→    features: [
 66→      'Tout Standard +',
 67→      'Badge "Premium Member"',
 68→      'Fiche enrichie (logo, vidéo, témoignages)',
 69→      'Mises à jour illimitées',
 70→      'Priorité dans les résultats',
 71→    ],
 72→  },
 73→  {
 74→    id: 'elite',
 75→    name: 'Elite',
 76→    requiredPlan: 'enterprise' as const,
 77→    planLabel: 'Agency',
 78→    price: 'Inclus',
 79→    icon: Crown,
 80→    color: 'purple',
 81→    colorClasses: 'text-purple-400 border-purple-500/20 bg-purple-500/5',
 82→    activeClasses: 'text-white border-purple-400/40 bg-purple-500/10 ring-2 ring-purple-400/30',
 83→    features: [
 84→      'Tout Premium +',
 85→      'Badge "Elite Member" doré',
 86→      'Position sponsorisée en tête',
 87→      'Analytics détaillés de visibilité IA',
 88→      'Support dédié + account manager',
 89→      'Multi-domaines',
 90→    ],
 91→  },
 92→];
 93→
 94→const getScoreColor = (s: number) => s >= 70 ? 'text-green-400' : s >= 50 ? 'text-yellow-400' : s >= 30 ? 'text-orange-400' : 'text-red-400';
 95→const getScoreBg = (s: number) => s >= 70 ? 'bg-green-500' : s >= 50 ? 'bg-yellow-500' : s >= 30 ? 'bg-orange-500' : 'bg-red-500';
 96→
 97→const Directory: React.FC<DirectoryProps> = ({ onBack, onViewEntity, onNavigateToPlan, user, directClientCount, maxClients, actionPlanComplete, actionPlanProgress, onNavigateToActionPlan }) => {
 98→  const [viewMode, setViewMode] = useState<'browse' | 'join'>('browse');
 99→  const [joinStep, setJoinStep] = useState<'form' | 'audit' | 'plan' | 'payment' | 'success'>('form');
100→  const [searchTerm, setSearchTerm] = useState('');
101→  const [selectedFilter, setSelectedFilter] = useState('All');
102→  const [showLimitAlert, setShowLimitAlert] = useState(false);
103→  const [showActionPlanAlert, setShowActionPlanAlert] = useState(false);
104→  const [isAuditing, setIsAuditing] = useState(false);
105→  const [auditScore, setAuditScore] = useState<number | null>(null);
106→  const [auditProgress, setAuditProgress] = useState(0);
107→  const [isProcessingPayment, setIsProcessingPayment] = useState(false);
108→
109→  useEffect(() => {
110→    if (showLimitAlert || showActionPlanAlert) { document.body.style.overflow = 'hidden'; }
111→    return () => { document.body.style.overflow = ''; };
112→  }, [showLimitAlert, showActionPlanAlert]);
113→
114→  const isAtLimit = directClientCount >= maxClients && user?.plan !== 'enterprise';
115→  const planLabel = user?.plan === 'free' ? 'Starter' : user?.plan === 'pro' ? 'Pro' : 'Agency';
116→
117→  // Map user plan to indexation tier
118→  const userIndexationPlan = user?.plan === 'enterprise' ? 'elite' : user?.plan === 'pro' ? 'premium' : 'standard';
119→
120→  const [formData, setFormData] = useState({
121→    companyName: '',
122→    website: '',
123→    sector: '',
124→    description: '',
125→    contactName: user?.name || '',
126→    contactEmail: user?.email || '',
127→  });
128→
129→  const handleJoinIndex = () => {
130→    // Priorité 1 : vérifier quota
131→    if (isAtLimit) {
132→      setShowLimitAlert(true);
133→      return;
134→    }
135→    // Priorité 2 : vérifier plan d'action complet
136→    if (!actionPlanComplete) {
137→      setShowActionPlanAlert(true);
138→      return;
139→    }
140→    setViewMode('join');
141→    setJoinStep('form');
142→    setAuditScore(null);
143→    setAuditProgress(0);
144→  };
145→
146→  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
147→    setFormData({ ...formData, [e.target.name]: e.target.value });
148→  };
149→
150→  const handleFormSubmit = (e: React.FormEvent) => {
151→    e.preventDefault();
152→    setJoinStep('audit');
153→    runAudit();
154→  };
155→
156→  const runAudit = () => {
157→    setIsAuditing(true);
158→    setAuditProgress(0);
159→    // Simulate audit progress
160→    const interval = setInterval(() => {
161→      setAuditProgress(prev => {
162→        if (prev >= 100) {
163→          clearInterval(interval);
164→          return 100;
165→        }
166→        return prev + Math.random() * 15 + 5;
167→      });
168→    }, 400);
169→
170→    setTimeout(() => {
171→      clearInterval(interval);
172→      setAuditProgress(100);
173→      const score = Math.floor(Math.random() * 45) + 20; // 20-65
174→      setAuditScore(score);
175→      setIsAuditing(false);
176→    }, 3500);
177→  };
178→
179→  const handlePayment = () => {
180→    setIsProcessingPayment(true);
181→    setTimeout(() => {
182→      setIsProcessingPayment(false);
183→      setJoinStep('success');
184→    }, 2500);
185→  };
186→
187→  const formValid = formData.companyName.trim() && formData.website.trim() && formData.sector && formData.contactEmail.trim();
188→
189→  const filteredDirectory = DIRECTORY_DATA.filter(item => {
190→    const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase()) || item.desc.toLowerCase().includes(searchTerm.toLowerCase());
191→    const matchesFilter = selectedFilter === 'All' || item.sector === selectedFilter;
192→    return matchesSearch && matchesFilter;
193→  });
194→
195→  const uniqueSectors = ['All', ...Array.from(new Set(DIRECTORY_DATA.map(item => item.sector)))];
196→
197→  const generateMockAnalysis = (item: typeof DIRECTORY_DATA[0]): AnalysisResult => {
198→    const url = `https://www.${item.name.toLowerCase()}.com`;
199→    const score = item.aeoScore;
200→    const isElite = score > 90;
201→    const categories: Record<string, CategoryScore> = {
202→      technical: { name: "Infrastructure Technique", score: isElite ? 95 : 85, weight: 10, items: [{ status: 'success', message: 'Temps de réponse TTFB < 100ms' }, { status: 'success', message: 'Rendu SSR optimisé' }] },
203→      entity: { name: "Autorité Entité", score, weight: 10, items: [{ status: 'success', message: 'Fiche Knowledge Graph détectée' }, { status: isElite ? 'success' : 'warning', message: isElite ? 'Page "À propos" détaillée' : 'Page "À propos" perfectible' }] },
204→      semantic: { name: "Structure Sémantique", score: score - 5, weight: 10, items: [{ status: 'success', message: 'Balisage Schema.org Organization valide' }, { status: 'success', message: 'Structure Hn logique' }] },
205→      content: { name: "Profondeur Contenu", score: score - 2, weight: 10, items: [{ status: 'success', message: 'Densité entités nommées élevée' }] },
206→    };
207→    return {
208→      url, timestamp: new Date().toISOString(), globalScore: score, categories, recommendations: [],
209→      aiCitation: { before: `Je n'ai pas d'informations précises sur ${item.name}.`, after: `D'après ses données structurées, ${item.name} est un leader en ${item.sector}.`, probability: Math.max(score - 10, 50) }
210→    };
211→  };
212→
213→  const handleViewDetails = (item: typeof DIRECTORY_DATA[0]) => {
214→    onViewEntity(generateMockAnalysis(item));
215→  };
216→
217→  // =============================================
218→  // BROWSER VIEW
219→  // =============================================
220→  const renderBrowser = () => (
221→    <div className="space-y-8 page-enter">
222→      <div className="text-center space-y-4 mb-12">
223→        <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">
224→          Annuaire <span className="text-purple-400 italic">Knowledge Graph</span>
225→        </h1>
226→        <p className="text-gray-500 text-lg max-w-2xl mx-auto">
227→          Explorez les entités certifiées AEO. Ces entreprises ont structuré leurs données pour être citées en priorité par ChatGPT, Claude, Gemini et AI Overviews.
228→        </p>
229→        <div className="flex justify-center gap-4 pt-4 items-center">
230→          {user && user.plan !== 'enterprise' && (
231→            <div className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-white/[0.03]/50 border border-[var(--border-subtle)] rounded-xl">
232→              <span className="text-[11px] text-gray-500">Quota projets</span>
233→              <span className={`text-sm font-bold ${isAtLimit ? 'text-red-400' : 'text-white'}`}>{directClientCount}/{maxClients}</span>
234→            </div>
235→          )}
236→          <button onClick={handleJoinIndex}
237→            className={`px-6 py-3 font-bold rounded-2xl transition-all flex items-center gap-2 transform hover:scale-105 ${
238→              isAtLimit ? 'bg-white/[0.06] border border-white/[0.06] text-gray-400 shadow-none' : !actionPlanComplete ? 'bg-white/[0.06] border border-amber-500/20 text-gray-300 shadow-none' : 'bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white shadow-lg shadow-purple-500/20'
239→            }`}>
240→            <Sparkles size={18} /> Rejoindre l'Index
241→            {isAtLimit ? <span className="text-[10px] ml-1 text-red-400">Limite</span> : !actionPlanComplete && <span className="text-[10px] ml-1 px-1.5 py-0.5 bg-amber-500/20 text-amber-400 rounded-full">Plan d'action</span>}
242→          </button>
243→        </div>
244→      </div>
245→
246→      <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white/[0.03] p-4 rounded-2xl border border-white/[0.06]">
247→        <div className="relative w-full md:w-96">
248→          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
249→          <input type="text" placeholder="Rechercher une entité..." className="w-full bg-black/40 border border-white/[0.06] rounded-2xl pl-10 pr-4 py-2.5 text-white focus:border-purple-500/50 outline-none" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
250→        </div>
251→        <div className="flex gap-2 overflow-x-auto w-full md:w-auto no-scrollbar pb-2 md:pb-0">
252→          {uniqueSectors.map(sector => (
253→            <button key={sector} onClick={() => setSelectedFilter(sector)}
254→              className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${selectedFilter === sector ? 'bg-white/20 text-white' : 'bg-transparent text-gray-500 hover:bg-purple-500/10'}`}>
255→              {sector}
256→            </button>
257→          ))}
258→        </div>
259→      </div>
260→
261→      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
262→        {/* Upsell Card */}
263→        <div className={`border border-dashed rounded-2xl p-6 flex flex-col items-center justify-center text-center transition-colors cursor-pointer group ${isAtLimit ? 'border-red-500/20 hover:bg-red-500/[0.02]' : !actionPlanComplete ? 'border-amber-500/20 hover:bg-amber-500/[0.02]' : 'border-white/20 hover:bg-white/[0.03]'}`} onClick={handleJoinIndex}>
264→          <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform ${isAtLimit ? 'bg-red-500/[0.06]' : !actionPlanComplete ? 'bg-amber-500/[0.06]' : 'bg-white/[0.03]'}`}>
265→            {isAtLimit ? <Lock size={28} className="text-red-400/60" /> : !actionPlanComplete ? <ClipboardList size={28} className="text-amber-400/60" /> : <Plus size={32} className="text-gray-500 group-hover:text-white" />}
266→          </div>
267→          <h3 className="font-bold text-white mb-1">{isAtLimit ? 'Limite atteinte' : !actionPlanComplete ? 'Plan d\'action requis' : 'Votre entreprise ici ?'}</h3>
268→          <p className="text-sm text-gray-500 mb-4">{isAtLimit ? `Votre plan ${planLabel} est limité à ${maxClients} projet${maxClients > 1 ? 's' : ''}.` : !actionPlanComplete ? `Complétez votre plan d'action (${actionPlanProgress.completed}/${actionPlanProgress.total}).` : "Rejoignez l'index et boostez votre visibilité IA."}</p>
269→          <span className={`text-sm font-bold flex items-center gap-1 group-hover:underline ${isAtLimit ? 'text-purple-400' : !actionPlanComplete ? 'text-amber-400' : 'text-purple-400'}`}>
270→            {isAtLimit ? 'Upgrader mon plan' : !actionPlanComplete ? 'Compléter le plan d\'action' : 'Ajouter mon site'} <ArrowRight size={14} />
271→          </span>
272→        </div>
273→
274→        {filteredDirectory.map((item) => (
275→          <div key={item.id} className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 rounded-2xl border border-white/[0.06] group hover:border-primary/30 transition-all hover:-translate-y-1 flex flex-col">
276→            <div className="flex justify-between items-start mb-4">
277→              <div className="flex items-center gap-3">
278→                <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-gray-800 to-black border border-white/[0.06] flex items-center justify-center text-white font-bold font-sans text-xl shadow-inner">{item.name.charAt(0)}</div>
279→                <div>
280→                  <h3 className="font-bold text-white flex items-center gap-1">{item.name} {item.verified && <Check size={14} className="text-purple-400" />}</h3>
281→                  <p className="text-xs text-gray-500">{item.sector}</p>
282→                </div>
283→              </div>
284→              <div className="flex flex-col items-end">
285→                <div className={`text-lg font-bold ${item.aeoScore >= 90 ? 'text-purple-300' : 'text-purple-400'}`}>{item.aeoScore}</div>
286→                <div className="text-[10px] text-gray-500 uppercase tracking-wider">AEO Score</div>
287→              </div>
288→            </div>
289→            <p className="text-sm text-gray-500 mb-6 line-clamp-2 h-10">{item.desc}</p>
290→            <div className="flex items-center justify-between pt-4 border-t border-[var(--border-subtle)] mt-auto">
291→              <span className={`text-xs px-2 py-1 rounded border ${item.status === 'Elite' ? 'bg-purple-500/10 border-purple-500/30 text-purple-400' : item.status === 'Premium' ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' : 'bg-gray-500/10 border-gray-500/30 text-gray-500'}`}>{item.status} Member</span>
292→              <button onClick={() => handleViewDetails(item)} className="text-xs text-white hover:text-purple-400 flex items-center gap-1 transition-colors">Voir la fiche <ArrowRight size={12} /></button>
293→            </div>
294→          </div>
295→        ))}
296→      </div>
297→    </div>
298→  );
299→
300→  // =============================================
301→  // JOIN FUNNEL
302→  // =============================================
303→  const renderJoinFunnel = () => {
304→    const steps = [
305→      { key: 'form', label: 'Entreprise' },
306→      { key: 'audit', label: 'Audit AEO' },
307→      { key: 'plan', label: 'Indexation' },
308→      { key: 'payment', label: 'Confirmation' },
309→    ];
310→    const currentStepIndex = steps.findIndex(s => s.key === joinStep);
311→
312→    return (
313→      <div className="max-w-2xl mx-auto page-enter">
314→        {/* Back + Title */}
315→        <button onClick={() => { setViewMode('browse'); setJoinStep('form'); }} className="flex items-center text-sm text-gray-500 hover:text-white mb-6 transition-colors group">
316→          <ArrowLeft size={16} className="mr-2 group-hover:-translate-x-1 transition-transform" /> Retour à l'annuaire
317→        </button>
318→
319→        <div className="text-center mb-8">
320→          <h2 className="text-3xl font-sans font-bold text-white mb-2">Rejoindre l'Index <span className="text-purple-400">CitedBy.ai</span></h2>
321→          <p className="text-gray-500 text-sm">Faites référencer votre entreprise dans l'annuaire Knowledge Graph</p>
322→        </div>
323→
324→        {/* Progress bar */}
325→        {joinStep !== 'success' && (
326→          <div className="flex items-center gap-2 mb-10">
327→            {steps.map((s, i) => (
328→              <React.Fragment key={s.key}>
329→                <div className="flex items-center gap-2">
330→                  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold border transition-all ${
331→                    i < currentStepIndex ? 'bg-purple-500 border-purple-500 text-white' :
332→                    i === currentStepIndex ? 'bg-purple-500/20 border-purple-500/50 text-purple-300' :
333→                    'bg-white/5 border-white/[0.06] text-gray-600'
334→                  }`}>
335→                    {i < currentStepIndex ? <Check size={14} /> : i + 1}
336→                  </div>
337→                  <span className={`text-xs font-medium hidden sm:block ${i <= currentStepIndex ? 'text-white' : 'text-gray-600'}`}>{s.label}</span>
338→                </div>
339→                {i < steps.length - 1 && <div className={`flex-1 h-px ${i < currentStepIndex ? 'bg-purple-500' : 'bg-white/10'}`} />}
340→              </React.Fragment>
341→            ))}
342→          </div>
343→        )}
344→
345→        {/* ---- STEP 1: FORM ---- */}
346→        {joinStep === 'form' && (
347→          <form onSubmit={handleFormSubmit} className="space-y-5">
348→            <div className="bg-white/[0.03] border border-[var(--border-subtle)] rounded-2xl p-6 space-y-4">
349→              <h3 className="text-lg font-bold text-white flex items-center gap-2 mb-2"><Building2 size={18} className="text-purple-400" /> Informations de l'entreprise</h3>
350→
351→              <div>
352→                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Nom de l'entreprise *</label>
353→                <input type="text" name="companyName" value={formData.companyName} onChange={handleInputChange} placeholder="Ex: MonEntreprise SAS" required
354→                  className="w-full bg-white/5 border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50" />
355→              </div>
356→
357→              <div>
358→                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">URL du site web *</label>
359→                <div className="relative">
360→                  <Globe size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
361→                  <input type="url" name="website" value={formData.website} onChange={handleInputChange} placeholder="https://www.monsite.fr" required
362→                    className="w-full bg-white/5 border border-white/[0.06] rounded-xl pl-10 pr-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50" />
363→                </div>
364→              </div>
365→
366→              <div>
367→                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Secteur d'activité *</label>
368→                <select name="sector" value={formData.sector} onChange={handleInputChange} required
369→                  className="w-full bg-white/5 border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-white focus:outline-none focus:border-purple-500/50 cursor-pointer">
370→                  <option value="" className="bg-[#111] text-gray-500">Sélectionnez un secteur</option>
371→                  {SECTORS.map(s => <option key={s} value={s} className="bg-[#111]">{s}</option>)}
372→                </select>
373→              </div>
374→
375→              <div>
376→                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Description courte</label>
377→                <textarea name="description" value={formData.description} onChange={handleInputChange} placeholder="Décrivez votre activité en 1-2 phrases..." rows={3}
378→                  className="w-full bg-white/5 border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 resize-none" />
379→              </div>
380→            </div>
381→
382→            <div className="bg-white/[0.03] border border-[var(--border-subtle)] rounded-2xl p-6 space-y-4">
